import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Bear 통합: 계획 자동 저장 | Plannotator","description":"Plannotator의 Bear 통합 구성 방법을 배웁니다. x-callback-url을 통해 승인된 계획을 자동 저장하고, 스마트 태그를 생성하며, 지식 축적 및 계획 아카이빙을 구현합니다.","frontmatter":{"title":"Bear 통합: 계획 자동 저장 | Plannotator","sidebarTitle":"Bear에 자동 저장","subtitle":"Bear 통합: 승인된 계획 자동 저장 | Plannotator","description":"Plannotator의 Bear 통합 구성 방법을 배웁니다. x-callback-url을 통해 승인된 계획을 자동 저장하고, 스마트 태그를 생성하며, 지식 축적 및 계획 아카이빙을 구현합니다.","tags":["통합","Bear","노트 앱","지식 축적"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"ko/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"ko/backnotprop/plannotator/advanced/bear-integration/index.md"}'),l={name:"ko/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(n,t,d,s,c,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="bear-통합-승인된-계획-자동-저장" tabindex="-1">Bear 통합: 승인된 계획 자동 저장 <a class="header-anchor" href="#bear-통합-승인된-계획-자동-저장" aria-label="Permalink to &quot;Bear 통합: 승인된 계획 자동 저장&quot;">​</a></h1><h2 id="학습-목표" tabindex="-1">학습 목표 <a class="header-anchor" href="#학습-목표" aria-label="Permalink to &quot;학습 목표&quot;">​</a></h2><p>Bear 통합을 활성화하면 계획을 승인할 때마다 Plannotator가 자동으로 Bear 노트에 계획을 저장합니다:</p><ul><li>자동 생성된 제목(계획에서 추출)</li><li>스마트 태그(프로젝트명, 키워드, 프로그래밍 언어)</li><li>완전한 계획 내용</li></ul><p>이렇게 하면 승인된 모든 계획을 한 곳에서 관리하여 나중에 검토하고 지식을 축적할 수 있습니다.</p><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p>다음과 같은 상황을 겪어보셨을 것입니다:</p><ul><li>AI가 생성한 계획이 좋지만 나중에 참고하기 위해 저장하고 싶음</li><li>Bear에 계획을 수동으로 복사하여 붙여넣는 것이 너무 번거로움</li><li>다른 프로젝트의 계획이 섞여 있어 태그 관리가 안 됨</li></ul><p>Bear 통합을 사용하면 이러한 문제가 자동으로 해결됩니다.</p><h2 id="이-방법이-필요한-상황" tabindex="-1">이 방법이 필요한 상황 <a class="header-anchor" href="#이-방법이-필요한-상황" aria-label="Permalink to &quot;이 방법이 필요한 상황&quot;">​</a></h2><ul><li>Bear를 주요 노트 앱으로 사용하는 경우</li><li>승인된 계획을 지식 베이스로 아카이빙해야 하는 경우</li><li>태그를 통해 과거 계획을 빠르게 검색하고 싶은 경우</li></ul><div class="info custom-block"><p class="custom-block-title">Bear란?</p><p>Bear는 macOS용 Markdown 노트 앱으로 태그, 암호화, 동기화 등의 기능을 지원합니다. 아직 설치하지 않았다면 <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a>에서 확인하세요.</p></div><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><ul><li>Plannotator 설치 완료(<a href="./../../start/installation-claude-code/">설치 가이드</a> 참조)</li><li>Bear 설치 및 정상 사용 가능</li><li>기본 계획 검토 프로세스 이해(<a href="./../../platforms/plan-review-basics/">계획 검토 기초</a> 참조)</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p>Bear 통합의 핵심은 <strong>x-callback-url</strong> 프로토콜입니다:</p><ol><li>Plannotator UI에서 Bear 통합 활성화(브라우저 localStorage에 저장)</li><li>계획 승인 시 Plannotator가 <code>bear://x-callback-url/create</code> URL 전송</li><li>시스템이 <code>open</code> 명령을 사용하여 자동으로 Bear를 열고 노트 생성</li><li>계획 내용, 제목, 태그가 자동으로 입력됨</li></ol><p><strong>주요 특징</strong>:</p><ul><li>vault 경로 구성 불필요(Obsidian처럼 vault를 지정할 필요 없음)</li><li>스마트 태그 생성(최대 7개)</li><li>계획 승인 시 자동 저장</li></ul><div class="tip custom-block"><p class="custom-block-title">Obsidian과의 차이점</p><p>Bear 통합은 더 간단하며 vault 경로를 구성할 필요가 없고 스위치만 있으면 됩니다. 하지만 Obsidian은 저장 폴더를 지정하고 더 많은 사용자 정의가 가능합니다.</p></div><h2 id="따라하기" tabindex="-1">따라하기 <a class="header-anchor" href="#따라하기" aria-label="Permalink to &quot;따라하기&quot;">​</a></h2><h3 id="_1단계-plannotator-설정-열기" tabindex="-1">1단계: Plannotator 설정 열기 <a class="header-anchor" href="#_1단계-plannotator-설정-열기" aria-label="Permalink to &quot;1단계: Plannotator 설정 열기&quot;">​</a></h3><p>AI Agent가 계획을 생성하고 Plannotator UI를 열면 오른쪽 상단의 ⚙️ <strong>Settings</strong> 버튼을 클릭합니다.</p><p><strong>확인해야 할 것</strong>: 여러 구성 옵션이 포함된 설정 패널이 팝업됩니다</p><h3 id="_2단계-bear-통합-활성화" tabindex="-1">2단계: Bear 통합 활성화 <a class="header-anchor" href="#_2단계-bear-통합-활성화" aria-label="Permalink to &quot;2단계: Bear 통합 활성화&quot;">​</a></h3><p>설정 패널에서 <strong>Bear Notes</strong> 섹션을 찾아 스위치 버튼을 클릭합니다.</p><p><strong>이유</strong> 스위치가 회색(비활성화)에서 파란색(활성화)으로 변경되고 동시에 브라우저의 localStorage에 저장됩니다.</p><p><strong>확인해야 할 것</strong>:</p><ul><li>Bear Notes 스위치가 파란색으로 변경됨</li><li>설명 텍스트: &quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="_3단계-계획-승인" tabindex="-1">3단계: 계획 승인 <a class="header-anchor" href="#_3단계-계획-승인" aria-label="Permalink to &quot;3단계: 계획 승인&quot;">​</a></h3><p>계획 검토를 완료한 후 하단의 <strong>Approve</strong> 버튼을 클릭합니다.</p><p><strong>이유</strong> Plannotator가 Bear 설정을 읽고 활성화되어 있으면 승인과 동시에 Bear의 x-callback-url을 호출합니다.</p><p><strong>확인해야 할 것</strong>:</p><ul><li>Bear 앱이 자동으로 열림</li><li>새 노트 창이 팝업됨</li><li>제목과 내용이 이미 자동으로 입력됨</li><li>태그가 자동으로 생성됨(<code>#</code>으로 시작)</li></ul><h3 id="_4단계-저장된-노트-확인" tabindex="-1">4단계: 저장된 노트 확인 <a class="header-anchor" href="#_4단계-저장된-노트-확인" aria-label="Permalink to &quot;4단계: 저장된 노트 확인&quot;">​</a></h3><p>Bear에서 새로 생성된 노트를 확인하여 다음을 확인합니다:</p><ul><li>제목이 올바른지(계획의 H1에서 가져옴)</li><li>내용이 완전한지(계획 전체 텍스트 포함)</li><li>태그가 합리적인지(프로젝트명, 키워드, 프로그래밍 언어)</li></ul><p><strong>확인해야 할 것</strong>: 다음과 같은 노트 구조:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[완전한 계획 내용...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>[ ] Settings에서 Bear Notes 스위치가 활성화됨</li><li>[ ] 계획 승인 후 Bear가 자동으로 열림</li><li>[ ] 노트 제목이 계획의 H1과 일치함</li><li>[ ] 노트에 완전한 계획 내용이 포함됨</li><li>[ ] 태그에 <code>#plannotator</code>와 프로젝트명이 포함됨</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><h3 id="bear가-자동으로-열리지-않음" tabindex="-1">Bear가 자동으로 열리지 않음 <a class="header-anchor" href="#bear가-자동으로-열리지-않음" aria-label="Permalink to &quot;Bear가 자동으로 열리지 않음&quot;">​</a></h3><p><strong>원인</strong>: 시스템 <code>open</code> 명령이 실패했을 수 있습니다:</p><ul><li>Bear가 설치되지 않았거나 App Store에서 다운로드하지 않음</li><li>Bear의 URL scheme이 다른 앱에 의해 가로채짐</li></ul><p><strong>해결책</strong>:</p><ol><li>Bear가 정상적으로 설치되었는지 확인</li><li>터미널에서 수동으로 테스트: <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="태그가-예상과-다름" tabindex="-1">태그가 예상과 다름 <a class="header-anchor" href="#태그가-예상과-다름" aria-label="Permalink to &quot;태그가 예상과 다름&quot;">​</a></h3><p><strong>원인</strong>: 태그는 자동으로 생성되며 규칙은 다음과 같습니다:</p><ul><li>필수: <code>#plannotator</code></li><li>필수: 프로젝트명(git 저장소명 또는 디렉토리명에서 추출)</li><li>선택: H1 제목에서 최대 3개의 키워드 추출(불용어 제외)</li><li>선택: 코드 블록에서 프로그래밍 언어 태그 추출(json/yaml/markdown 제외)</li><li>최대 7개 태그</li></ul><p><strong>해결책</strong>:</p><ul><li>태그가 예상과 다르면 Bear에서 수동으로 편집 가능</li><li>프로젝트명이 잘못되었다면 git 저장소 구성 또는 디렉토리명 확인</li></ul><h3 id="승인했지만-저장되지-않음" tabindex="-1">승인했지만 저장되지 않음 <a class="header-anchor" href="#승인했지만-저장되지-않음" aria-label="Permalink to &quot;승인했지만 저장되지 않음&quot;">​</a></h3><p><strong>원인</strong>:</p><ul><li>Bear 스위치가 활성화되지 않음(Settings 확인)</li><li>네트워크 오류 또는 Bear 응답 시간 초과</li><li>계획 내용이 비어 있음</li></ul><p><strong>해결책</strong>:</p><ol><li>Settings에서 스위치가 파란색(활성화 상태)인지 확인</li><li>터미널에 오류 로그가 있는지 확인(<code>[Bear] Save failed:</code>)</li><li>계획을 다시 승인</li></ol><h2 id="태그-생성-메커니즘-상세-설명" tabindex="-1">태그 생성 메커니즘 상세 설명 <a class="header-anchor" href="#태그-생성-메커니즘-상세-설명" aria-label="Permalink to &quot;태그 생성 메커니즘 상세 설명&quot;">​</a></h2><p>Plannotator는 스마트 태그를 생성하여 Bear에서 계획을 빠르게 검색할 수 있도록 합니다. 다음은 태그 생성 규칙입니다:</p><table tabindex="0"><thead><tr><th>태그 소스</th><th>예시</th><th>우선순위</th></tr></thead><tbody><tr><td>고정 태그</td><td><code>#plannotator</code></td><td>필수</td></tr><tr><td>프로젝트명</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>필수</td></tr><tr><td>H1 키워드</td><td><code>#authentication</code>, <code>#api</code></td><td>선택(최대 3개)</td></tr><tr><td>프로그래밍 언어</td><td><code>#typescript</code>, <code>#python</code></td><td>선택</td></tr></tbody></table><p><strong>불용어 목록</strong>(태그로 사용되지 않음):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>프로그래밍 언어 제외</strong>(태그로 사용되지 않음):</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>예시: 태그 생성 과정</summary><p>계획 제목이 &quot;Implementation Plan: User Authentication System in TypeScript&quot;이고 코드 블록에 Python과 JSON이 포함되어 있다고 가정합니다:</p><ol><li><strong>고정 태그</strong>: <code>#plannotator</code></li><li><strong>프로젝트명</strong>: <code>#myproject</code>(git 저장소명 가정)</li><li><strong>H1 키워드</strong>: <ul><li><code>implementation</code> → 제외(불용어)</li><li><code>plan</code> → 제외(불용어)</li><li><code>user</code> → 유지 → <code>#user</code></li><li><code>authentication</code> → 유지 → <code>#authentication</code></li><li><code>system</code> → 유지 → <code>#system</code></li><li><code>typescript</code> → 유지 → <code>#typescript</code></li></ul></li><li><strong>프로그래밍 언어</strong>: <ul><li><code>python</code> → 유지 → <code>#python</code></li><li><code>json</code> → 제외(제외 목록)</li></ul></li></ol><p>최종 태그: <code>#plannotator #myproject #user #authentication #system #typescript #python</code>(7개, 상한선 도달)</p></details><h2 id="obsidian-통합과-비교" tabindex="-1">Obsidian 통합과 비교 <a class="header-anchor" href="#obsidian-통합과-비교" aria-label="Permalink to &quot;Obsidian 통합과 비교&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>Bear 통합</th><th>Obsidian 통합</th></tr></thead><tbody><tr><td>구성 복잡도</td><td>간단(스위치만)</td><td>중간(vault 및 폴더 선택 필요)</td></tr><tr><td>저장</td><td>Bear 앱 내부</td><td>지정된 vault 경로</td></tr><tr><td>파일명</td><td>Bear가 자동 관리</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>없음(Bear 미지원)</td><td>있음(created, source, tags)</td></tr><tr><td>크로스 플랫폼</td><td>macOS만</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ 사용</td><td>❌ 파일 직접 작성</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">선택 방법</p><ul><li>macOS만 사용하고 Bear를 선호한다면: Bear 통합이 더 간단함</li><li>크로스 플랫폼이 필요하거나 저장 경로를 사용자 정의하려면: Obsidian 통합이 더 유연함</li><li>둘 다 사용하고 싶다면: 동시에 활성화 가능(계획 승인 시 두 곳에 모두 저장됨)</li></ul></div><h2 id="이번-강의-요약" tabindex="-1">이번 강의 요약 <a class="header-anchor" href="#이번-강의-요약" aria-label="Permalink to &quot;이번 강의 요약&quot;">​</a></h2><ul><li>Bear 통합은 x-callback-url 프로토콜을 통해 작동하며 구성이 간단함</li><li>Settings에서 스위치만 켜면 되고 경로를 지정할 필요 없음</li><li>계획 승인 시 자동으로 Bear에 저장됨</li><li>스마트 태그 생성, 프로젝트명, 키워드, 프로그래밍 언어 포함(최대 7개)</li><li>Obsidian 통합에 비해 Bear가 더 간단하지만 기능은 적음</li></ul><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../remote-mode/">원격/Devcontainer 모드</a>**를 배웁니다.</p><p>배울 내용:</p><ul><li>원격 환경(SSH, devcontainer, WSL)에서 Plannotator를 사용하는 방법</li><li>고정 포트 및 포트 포워딩 구성</li><li>원격 환경에서 브라우저를 열어 검토 페이지 보기</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보기</strong></summary><blockquote><p>업데이트: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인</th></tr></thead><tbody><tr><td>Bear 구성 인터페이스</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Bear에 저장</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>태그 추출</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>제목 추출</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Bear 설정 인터페이스</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Bear 설정 읽기</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Bear 설정 저장</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI 설정 컴포넌트</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>승인 시 Bear 호출</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>서버 Bear 처리</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>주요 함수</strong>:</p><ul><li><code>saveToBear(config: BearConfig)</code>: x-callback-url을 통해 계획을 Bear에 저장</li><li><code>extractTags(markdown: string)</code>: 계획 내용에서 스마트 태그 추출(최대 7개)</li><li><code>extractTitle(markdown: string)</code>: 계획의 H1 제목에서 노트 제목 추출</li><li><code>getBearSettings()</code>: localStorage에서 Bear 통합 설정 읽기</li><li><code>saveBearSettings(settings)</code>: Bear 통합 설정을 localStorage에 저장</li></ul><p><strong>주요 상수</strong>:</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>: localStorage의 Bear 설정 키명</li></ul><p><strong>Bear URL 형식</strong>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
